    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});
  // Batterfly at dist 1, cx=592 cy=0 (top edge) — click near top
  await click(592, 50);
  await page.waitForTimeout(7000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ pos: s.player_position, stats: s.player_stats, mobs: (s.nearby_entities||[]).filter(e=>e.type===3).slice(0,5).map(e=>({name:e.name,hp:e.hp,dist:e.distance,cx:e.click_x,cy:e.click_y,on_screen:e.on_screen})), drops: (s.nearby_entities||[]).filter(e=>e.type===4).slice(0,3).map(e=>({name:e.name,dist:e.distance,cx:e.click_x,cy:e.click_y,on_screen:e.on_screen})) });
  });
  return state;
}

