async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});
  // Keep chopping - alternate between nearby Oaks
  for (let i = 0; i < 10; i++) {
    await click(592, 5);
    await page.waitForTimeout(3500);
    // Check log count
    const logs = await page.evaluate(() => {
      const s = window.__latestGameState;
      return (s.inventory||[]).filter(it=>it.key==='logs').reduce((sum,it)=>sum+it.count,0);
    });
    if (logs >= 10) break;
    // Also try the second oak
    await click(976, 5);
    await page.waitForTimeout(3500);
    const logs2 = await page.evaluate(() => {
      const s = window.__latestGameState;
      return (s.inventory||[]).filter(it=>it.key==='logs').reduce((sum,it)=>sum+it.count,0);
    });
    if (logs2 >= 10) break;
  }
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const totalLogs = (s.inventory||[]).filter(it=>it.key==='logs').reduce((sum,it)=>sum+it.count,0);
    return JSON.stringify({ pos: s.player_position, stats: s.player_stats, totalLogs, inventory: s.inventory });
  });
  return state;
}

