    // Get fresh positions each iteration
    const data = await page.evaluate(() => {
      const g = window.game;
      const player = g.player;
      const entities = g.entities?.entities || {};
      const oaks = [];
      for (const [id, ent] of Object.entries(entities)) {
        if (ent?.name === 'Oak') {
          const dx = ent.gridX - player.gridX;
          const dy = ent.gridY - player.gridY;
          oaks.push({ x: ent.gridX, y: ent.gridY, dx, dy, dist: Math.abs(dx)+Math.abs(dy) });
        }
      }
      oaks.sort((a,b) => a.dist - b.dist);
      return { px: player.gridX, py: player.gridY, oaks: oaks.slice(0, 3) };
    });

    if (data.oaks.length === 0) break;
    const oak = data.oaks[0];
    const sx = CANVAS_CX + oak.dx * TILE;
    const sy = CANVAS_CY + oak.dy * TILE;

    // Walk toward oak if too far, or click directly
    if (oak.dist > 5) {
      // Walk closer first
      const wx = Math.max(50, Math.min(1230, CANVAS_CX + (oak.dx > 0 ? 200 : -200)));
