  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ pos: s.player_position, totalLogs: (s.inventory||[]).filter(it=>it.key==='logs').reduce((sum,it)=>sum+it.count,0), inventory: s.inventory });
  });
  return state;
}

