        .sort((a,b) => a.dist - b.dist);
      return { oaks: oaks.slice(0, 3) };
    });

    if (!data.oaks.length) break;
    const oak = data.oaks[0];
    if (oak.dist > 3) {
      await click(Math.max(50, Math.min(1230, CANVAS_CX + (oak.dx > 0 ? 300 : -300))), Math.max(50, Math.min(690, CANVAS_CY + (oak.dy > 0 ? 200 : -200))));
      await page.waitForTimeout(2500);
      continue;
    }
    await click(Math.max(20, Math.min(1260, CANVAS_CX + oak.dx * TILE)), Math.max(20, Math.min(720, CANVAS_CY + oak.dy * TILE)));
    await page.waitForTimeout(4000);
    totalLogs = await page.evaluate(() => (window.__latestGameState?.inventory||[]).filter(it=>it.key==='logs').reduce((s,it)=>s+it.count,0));
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ totalLogs, pos: await page.evaluate(() => window.__latestGameState?.player_position) });
}

