    return { pos: { x: p.gridX, y: p.gridY }, inv: inv.map(i=>i.name), quest };
  });

  // Calculate screen position for Crab at (186, 216) from player at (181, 207)
  const target = await page.evaluate(() => {
    const g = window.game, p = g.player;
    const cam = g.renderer.camera;
    // Walk to Crab at (186, 216)
    const crab = Object.values(g.entities?.entities || {}).find(e => e?.name === 'Crab' && e.gridX === 186 && e.gridY === 216);
    if (!crab) {
      // find nearest crab
      const c = Object.values(g.entities?.entities || {}).filter(e => e?.name === 'Crab').sort((a,b) => Math.abs(a.gridX - p.gridX) + Math.abs(a.gridY - p.gridY) - Math.abs(b.gridX - p.gridX) - Math.abs(b.gridY - p.gridY))[0];
      if (!c) return null;
      return { sx: Math.round((c.gridX*16 - cam.x)*3), sy: Math.round((c.gridY*16 - cam.y)*3), x: c.gridX, y: c.gridY };
    }
    return { sx: Math.round((crab.gridX*16 - cam.x)*3), sy: Math.round((crab.gridY*16 - cam.y)*3), x: crab.gridX, y: crab.gridY };
  });
  console.log('Nearest Crab:', JSON.stringify(target));

  if (target) {
    // Walk toward the crab (onto the beach)
    const sx = Math.min(Math.max(target.sx, 50), 1200);
    const sy = Math.min(Math.max(target.sy, 50), 700);
