    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  const getState = () => page.evaluate(() => {
    const g = window.game, p = g.player;
    const cam = g.renderer.camera;
    const inv = window.__latestGameState?.inventory || [];
    const quest = window.__latestGameState?.quests?.find(q => q.key === 'anvilsechoes');
    const all = Object.values(g.entities?.entities || {})
      .filter(e => e && e.name && Math.abs(e.gridX - p.gridX) + Math.abs(e.gridY - p.gridY) < 20)
      .map(e => ({ name: e.name, type: e.type, x: e.gridX, y: e.gridY, dist: Math.abs(e.gridX - p.gridX) + Math.abs(e.gridY - p.gridY) }))
      .sort((a,b) => a.dist - b.dist);
    return { pos: { x: p.gridX, y: p.gridY }, inv: inv.map(i=>i.name), quest: quest?.stage, drops: all.filter(e=>e.type===4) };
  });

  // Walk east toward (201, 208) — where I saw a grey item
  // From (158, 220), need to go east ~43 and north ~12
  for (let i = 0; i < 6; i++) {
