async (page) => {
  // Get camera and calculate position of building door
  const cam = await page.evaluate(() => ({ x: window.game.camera.x, y: window.game.camera.y }));

  // Try different door tile positions around x=171-175, y=172-175
  const doorCandidates = [
    {x: 171, y: 172}, {x: 172, y: 172}, {x: 173, y: 172}, {x: 174, y: 172},
    {x: 171, y: 173}, {x: 172, y: 173}, {x: 173, y: 173}, {x: 174, y: 173},
    {x: 172, y: 174}, {x: 173, y: 174},
  ];

  for (const pos of doorCandidates) {
    const sx = (pos.x * 16 - cam.x) * 3;
    const sy = (pos.y * 16 - cam.y) * 3;
    if (sx >= 0 && sx <= 1280 && sy >= 0 && sy <= 720) {
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, {x: sx, y: sy});
      await page.waitForTimeout(1500);

      const state = await page.evaluate(() => window.__latestGameState);
      const p = state.player_position;
      // Check if we got teleported (entered a building)
      if (p.y > 800 || p.x < 100) {
        return JSON.stringify({ teleported: true, pos: p, tried: pos });
      }
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => window.__latestGameState);
  return JSON.stringify({ pos: state.player_position, msg: 'no teleport found' });
}

