async (page) => {
  // Calculate exact screen position for tile (199, 149)
  const screenPos = await page.evaluate(() => {
    const cam = window.game.camera;
    const tx = 199, ty = 149;
    const sx = (tx * 16 - cam.x) * 3;
    const sy = (ty * 16 - cam.y) * 3;
    return { sx: Math.round(sx), sy: Math.round(sy) };
  });

  // Click the portal tile directly
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: Math.min(Math.max(screenPos.sx, 50), 1230), y: Math.min(Math.max(screenPos.sy, 50), 670) });
  await page.waitForTimeout(5000);

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({ screenPos, pos });
}

