async (page) => {
  const result = await page.evaluate(() => {
    try {
      // Check game's entity manager for chests and items
      const game = window.game;
      const entities = game.entities;

      // Try to find chest entities
      const chests = [];
      const itemDrops = [];

      if (entities && entities.entities) {
        Object.values(entities.entities).forEach(e => {
          const name = e.name || '';
          if (name.toLowerCase().includes('hammer') || name.toLowerCase().includes('chest')) {
            chests.push({name: e.name, x: e.gridX, y: e.gridY, type: e.type});
          }
          if (e.type === 4 || e.type === 'item') {
            itemDrops.push({name: e.name, x: e.gridX, y: e.gridY});
          }
        });
      }

      // Try alternate path
      const entityKeys = entities ? Object.keys(entities) : [];

      return JSON.stringify({chests, itemDrops, entityKeys: entityKeys.slice(0, 20)});
    } catch(e) {
      return JSON.stringify({error: e.message});
    }
  });
  return result;
}

