async (page) => {
  // Get camera and compute click positions
  const camData = await page.evaluate(() => {
    const cam = window.game.camera;
    return {cx: cam.x, cy: cam.y};
  });

  const {cx, cy} = camData;

  // Target: just north of bridge at (213, 157)
  const tx = 213, ty = 157;
  const sx = Math.round((tx*16 - cx)*3);
  const sy = Math.round((ty*16 - cy)*3);
  const clickX = Math.max(10, Math.min(1270, sx));
  const clickY = Math.max(10, Math.min(710, sy));

  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x: clickX, y: clickY});

  await page.waitForTimeout(3000);
  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({camData, target:{tx,ty}, screen:{sx,sy}, clickAt:{clickX,clickY}, pos});
}

